import { navigateInAppPath, type InAppNavigateFn } from '../router/navigateInAppPath';
import type { OpenWorkspaceTabInput } from '../workspace/workspaceTabTypes';

export type { OpenWorkspaceTabInput };

/**
 * Opens a workspace tab (shell multi-tab) when `WorkspaceTabProvider` is mounted;
 * otherwise falls back to shell-safe in-app navigation.
 */
export function openWorkspaceTab(
  input: OpenWorkspaceTabInput,
  navigate: InAppNavigateFn,
): void {
  if (typeof window.__LINM_OPEN_WORKSPACE_TAB__ === 'function') {
    window.__LINM_OPEN_WORKSPACE_TAB__(input);
    return;
  }
  navigateInAppPath(input.path, navigate);
}
